import '../css/roundedTextBox.css';
import '../css/basics.css';
import '../css/authentication.css';
import '../css/font.css';
import '../css/checkbox.css';
import InputWithImage from './components/InputWithImage';
import LoginButton from './components/RedButton';

const Login = ({ onLogin, changeOnRegisterPage }) => {

      const [username, setUsername] = useState('');
      const [password, setPassword] = useState('');

  return (
    <div className="authentication_block">
      <div className="authentication_textboxes_block">
        <header className="login_margin_top login_margin_left">Sign In</header>

        <InputWithImage
          icon="/images/icons/username.svg"
          alt="username"
          placeholder="Enter Username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />

        <InputWithImage
          icon="/images/icons/black_password.svg"
          alt="password"
          placeholder="Enter Password"
          type="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <div className="horizontal left gap10 login_margin_left">
          <input type="checkbox" className="center" />
          <label className="nowrap center margin_top_1 light">Remember Me</label>
        </div>

        <LoginButton text="Login" onClick={onLogin} />

        <div className="login_margin_left icon_line">
          <label>Or, Login with</label>
          <img src="/images/icons/facebook.svg" alt="facebook" />
          <img src="/images/icons/google.svg" alt="google" />
          <img src="/images/icons/x.svg" alt="x" />
        </div>

        <div className="login_margin_left">
          <label>Don't have an account? </label>
          <label className="blue_text" onClick={changeOnRegisterPage}>Create One</label>
        </div>
      </div>

      <div className="authentication_image_block">
        <img src="/images/login.png" alt="login" className="login_image" />
      </div>
    </div>
  );
};

export default Login;
